{
  "users": [
    {% for row in rows %}
    {
      "external_user_id": "{{ row['user_id'] | default: '' }}",
      "braze_id": "{{ row['braze_user_id_latest'] | default: '' }}",
      "attributes": {
        "guided_scripture_interaction_has_ever_flag": {{ row['guided_scripture_interaction_has_ever_flag'] | default: false }},
        "guided_prayer_interaction_has_ever_flag": {{ row['guided_prayer_interaction_has_ever_flag'] | default: false }},
        "audio_bible_interaction_has_ever_flag": {{ row['audio_bible_interaction_has_ever_flag'] | default: false }},
        "plan_audio_interaction_has_ever_flag": {{ row['plan_audio_interaction_has_ever_flag'] | default: false }},
        "plan_interaction_has_ever_flag": {{ row['plan_interaction_has_ever_flag'] | default: false }},
        "plan_subscribed_has_ever_flag": {{ row['plan_subscribed_has_ever_flag'] | default: false }},
        "plan_day_completion_has_ever_flag": {{ row['plan_day_completion_has_ever_flag'] | default: false }},
        "pmt_participation_has_ever_flag": {{ row['pmt_participation_has_ever_flag'] | default: false }},
        "votd_interaction_has_ever_flag": {{ row['votd_interaction_has_ever_flag'] | default: false }},
        "votd_share_has_ever_flag": {{ row['votd_share_has_ever_flag'] | default: false }}
      }
    }{% unless forloop.last %},{% endunless %}
    {% endfor %}
  ]
}
